import requests
from urllib.parse import urlparse

def fetch_and_display_url(url: str, timeout: int = 10) -> str:
    parsed = urlparse(url)
    if parsed.scheme not in {"http", "https"} or not parsed.netloc:
        raise ValueError("Invalid URL. Only http and https URLs are allowed.")

    response = requests.get(url, timeout=timeout)
    response.raise_for_status()
    content = response.text
    print(content)
    return content


def process_webhook(payload: dict) -> dict:
    """
    Flexible webhook processor for partner integrations.

    Expected payload example:
    {
        "integration": "partner_name",
        "url": "https://example.com/webhook",
        "data": {...}
    }
    """
    integration = payload.get("integration", "unknown")
    url = payload.get("url")

    if not url:
        raise ValueError("Missing 'url' in payload.")

    content = fetch_and_display_url(url)

    return {
        "integration": integration,
        "url": url,
        "content_length": len(content),
        "status": "processed",
    }